// Matrix Rain
// Adapted from GenerativeArtGallery / artwork5

let mrDrops = [];
let mrPrevSpacing = 0;

let mrGlyphs = {
  katakana: 'アイウエオカキクケコサシスセソタチツテトナニヌネノハヒフヘホマミムメモヤユヨラリルレロワン',
  latin:    'ABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789',
  symbols:  '∑∆∇∞∂∫≈≠≤≥×÷±√⊕⊗⊂⊃∈∃∀⌘★◊❄☯⚡',
  mixed:    'アカ∑∆AB01⊕≈★◊⌘∞01アイ∇≠'
};

function mrInit(spacing) {
  mrDrops = [];
  let cols = Math.floor(400 / spacing);
  for (let i = 0; i < cols; i++) {
    mrDrops.push({
      x: i * spacing + spacing / 2,
      y: -Math.random() * 400,
      speed: 3 + Math.random() * 6,
      chars: [],
      tick: 0
    });
  }
}

p.setup = function() {
  p.createCanvas(400, 400);
  p.colorMode(p.HSB, 360, 100, 100, 100);
  p.textFont('monospace');
  p.frameRate(30);
  mrInit(20);
};

p.draw = function() {
  let glyphStr = p.getSynthVar('glyph_set') || 'katakana';
  let speedStr = p.getSynthVar('drop_speed') || 'medium';
  let trailStr = p.getSynthVar('trail_length') || 'medium';
  let colorStr = p.getSynthVar('color_mode') || 'matrix';
  let densStr  = p.getSynthVar('density') || 'medium';

  let pool     = mrGlyphs[glyphStr] || mrGlyphs.katakana;
  let spacing  = densStr === 'sparse' ? 28 : densStr === 'medium' ? 20 : 14;
  let spdMult  = speedStr === 'slow' ? 0.5 : speedStr === 'medium' ? 1 : 2;
  let trailLen = trailStr === 'short' ? 5 : trailStr === 'medium' ? 12 : 24;
  let hue      = colorStr === 'matrix' ? 120 : colorStr === 'neon' ? 300 : colorStr === 'amber' ? 35 : 195;

  if (spacing !== mrPrevSpacing) { mrInit(spacing); mrPrevSpacing = spacing; }

  p.background(0, 0, 4, 35);
  p.textSize(13);
  p.textAlign(p.CENTER, p.CENTER);

  mrDrops.forEach(function(d) {
    d.y += d.speed * spdMult;
    d.tick++;
    if (d.tick % 3 === 0) {
      d.chars.unshift(pool[Math.floor(Math.random() * pool.length)]);
      if (d.chars.length > trailLen) d.chars.pop();
    }

    for (let i = 0; i < d.chars.length; i++) {
      let gy = d.y - i * 14;
      if (gy < -10 || gy > 410) continue;
      let alpha  = i === 0 ? 100 : p.map(i, 0, d.chars.length, 88, 5);
      let bright = i === 0 ? 100 : p.map(i, 0, d.chars.length, 80, 14);
      let sat    = i === 0 ? 5 : 82;
      p.fill(hue, sat, bright, alpha);
      p.text(d.chars[i], d.x, gy);
    }

    if (d.y - d.chars.length * 14 > 410) {
      d.y = -Math.random() * 350;
      d.speed = (3 + Math.random() * 6) * spdMult;
      d.chars = [];
    }
  });
};
